import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.DrTRbHdy.js";const p=JSON.parse('{"title":"地图类库设计文档（Vite 库模式）","description":"","frontmatter":{},"headers":[],"relativePath":"DESIGN.md","filePath":"DESIGN.md"}'),d={name:"DESIGN.md"};function l(i,e,n,s,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="地图类库设计文档-vite-库模式" tabindex="-1">地图类库设计文档（Vite 库模式） <a class="header-anchor" href="#地图类库设计文档-vite-库模式" aria-label="Permalink to &quot;地图类库设计文档（Vite 库模式）&quot;">​</a></h1><h2 id="_1-概述" tabindex="-1">1. 概述 <a class="header-anchor" href="#_1-概述" aria-label="Permalink to &quot;1. 概述&quot;">​</a></h2><p>本库提供一种可发布到 npm 的<strong>地图类</strong>，基于 <strong>OpenLayers</strong> 实现地图能力，界面层由 <strong>Vue 3</strong> 构建并打包进库内。使用 <strong>Vite</strong> 的库模式进行构建，面向 JavaScript 使用者。</p><h3 id="_1-1-目标" tabindex="-1">1.1 目标 <a class="header-anchor" href="#_1-1-目标" aria-label="Permalink to &quot;1.1 目标&quot;">​</a></h3><ul><li>单一入口：通过 <code>new MapClass(options)</code> 初始化。</li><li>核心地图：依赖 <strong>OpenLayers</strong>（<code>ol</code>），不打包进库，安装本库时自动安装。</li><li>界面：Vue 3 与 lucide-vue-next 打包进库，使用方无需安装。</li><li>构建：Vite 库模式，产出 ESM + UMD + CSS。</li></ul><h2 id="_2-技术架构" tabindex="-1">2. 技术架构 <a class="header-anchor" href="#_2-技术架构" aria-label="Permalink to &quot;2. 技术架构&quot;">​</a></h2><h3 id="_2-1-依赖策略" tabindex="-1">2.1 依赖策略 <a class="header-anchor" href="#_2-1-依赖策略" aria-label="Permalink to &quot;2.1 依赖策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>依赖</th><th>角色</th><th>说明</th></tr></thead><tbody><tr><td><strong>ol</strong> (OpenLayers)</td><td>依赖 (不打包)</td><td>构建时 external，安装本库时自动安装，运行时由依赖的 <code>ol</code> 提供。</td></tr><tr><td><strong>vue</strong>、<strong>lucide-vue-next</strong></td><td>打包进库</td><td>构建时打入产物，使用方无需安装。</td></tr></tbody></table><h3 id="_2-2-整体结构" tabindex="-1">2.2 整体结构 <a class="header-anchor" href="#_2-2-整体结构" aria-label="Permalink to &quot;2.2 整体结构&quot;">​</a></h3><p>使用方项目安装 openlayers + 本库，通过 MapClass 创建 OL Map 并挂载 Vue 应用；Vue 与 OL 共享 container，OL 占满容器，Vue 控件层绝对定位浮于其上。</p><h3 id="_2-3-目录结构" tabindex="-1">2.3 目录结构 <a class="header-anchor" href="#_2-3-目录结构" aria-label="Permalink to &quot;2.3 目录结构&quot;">​</a></h3><ul><li><code>src/index.js</code> 库入口；<code>MapClass.js</code> 地图类；<code>ol/createMap.js</code> 创建 Map；<code>vue/</code> 下 App 与 components。</li></ul><h2 id="_3-核心-api-设计" tabindex="-1">3. 核心 API 设计 <a class="header-anchor" href="#_3-核心-api-设计" aria-label="Permalink to &quot;3. 核心 API 设计&quot;">​</a></h2><ul><li>构造函数：<code>new MapClass({ container, center, zoom, layers, ... })</code></li><li>实例方法：<code>getMap()</code>、<code>getTimelineCurrentTime()</code>、<code>setTimelineToNow()</code>、<code>destroy()</code></li><li>与 OpenLayers 的边界：仅使用 OL 公开 API，不修改源码；peer 约定 <code>ol</code> 版本。</li></ul><h2 id="_4-构建与发布" tabindex="-1">4. 构建与发布 <a class="header-anchor" href="#_4-构建与发布" aria-label="Permalink to &quot;4. 构建与发布&quot;">​</a></h2><ul><li>入口 <code>src/index.js</code>；产物 ESM + UMD；<code>ol</code> 外部化，Vue 打包进库；样式单独 CSS。</li><li>使用方：<code>npm install CelestiaWeather</code>，引入 <code>style.css</code> 与 <code>MapClass</code>。</li></ul><h2 id="_5-风险与注意事项" tabindex="-1">5. 风险与注意事项 <a class="header-anchor" href="#_5-风险与注意事项" aria-label="Permalink to &quot;5. 风险与注意事项&quot;">​</a></h2><ul><li>容器内先 OL target 再 Vue 挂载点；样式用 BEM/CSS 变量；多实例各自独立 Vue App + OL Map。</li></ul><h2 id="_6-总结" tabindex="-1">6. 总结 <a class="header-anchor" href="#_6-总结" aria-label="Permalink to &quot;6. 总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>决策</th></tr></thead><tbody><tr><td>构建工具</td><td>Vite 库模式</td></tr><tr><td>语言</td><td>JavaScript</td></tr><tr><td>地图引擎</td><td>ol / OpenLayers（依赖，不打包）</td></tr><tr><td>界面</td><td>Vue 3（打包进库）</td></tr><tr><td>入口 API</td><td>单类 MapClass + options</td></tr><tr><td>产物</td><td>ESM + UMD + CSS</td></tr></tbody></table>',20)])])}const _=t(d,[["render",l]]);export{p as __pageData,_ as default};
